// ============================================================
// BL: LLExeter (CMPO) Stock Sync v1
// API: http://api.llexeter.co.uk — no auth required
// /stocklist  → {SKU: qty, ...}  (all stock levels)
// /code/{sku} → full product data for new products
// ============================================================

const SUPABASE_URL = 'https://ddjuoeyaoxllockcusgf.supabase.co';
const SERVICE_KEY  = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImRkanVvZXlhb3hsbG9ja2N1c2dmIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc2NTM4ODM3OSwiZXhwIjoyMDgwOTY0Mzc5fQ.tQTpdQCkE-V-aCfdt7GgN5FF-IdXQzGCAEuRE6gNupE';
const LLEXETER_BASE = 'http://api.llexeter.co.uk';
const CHUNK_SIZE   = 500;
const MAX_NEW_PER_RUN = 200; // cap new product enrichment per run to avoid timeout
const MIN_PRICE    = 20;    // skip products under £20

const EXCLUDE_TERMS = [
  'bolt', 'bolts', 'nut', 'nuts', 'screw', 'screws',
  'fastener', 'fasteners', 'washer', 'washers',
  'rivet', 'rivets', 'split pin', 'circlip',
  'o-ring', 'o ring', 'oring'
];

const now = new Date().toISOString();

// ── Step 1: Fetch stocklist from LLExeter API ─────────────────
let stocklist;
try {
  const res = await fetch(`${LLEXETER_BASE}/stocklist`);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  stocklist = await res.json();
} catch (err) {
  throw new Error('LLExeter /stocklist failed: ' + err.message);
}

const allSkus = Object.keys(stocklist);
if (allSkus.length === 0) throw new Error('Empty stocklist response from LLExeter');

// ── Step 2: Get existing LLEXETER SKUs from Supabase ──────────
let existingSkus = new Set();
try {
  // Fetch in pages (Supabase default limit 1000)
  let offset = 0;
  while (true) {
    const res = await fetch(
      `${SUPABASE_URL}/rest/v1/products?supplier_id=eq.LLEXETER&select=sku&limit=1000&offset=${offset}`,
      { headers: { 'apikey': SERVICE_KEY, 'Authorization': `Bearer ${SERVICE_KEY}` } }
    );
    const rows = await res.json();
    if (!Array.isArray(rows) || rows.length === 0) break;
    rows.forEach(r => existingSkus.add(r.sku));
    if (rows.length < 1000) break;
    offset += 1000;
  }
} catch (err) {
  throw new Error('Supabase fetch of existing SKUs failed: ' + err.message);
}

// ── Step 3: Partition into existing (stock update) vs new ─────
const stockUpdates = [];
const newSkus = [];

for (const [sku, qty] of Object.entries(stocklist)) {
  const stock_level = qty <= 3 ? 0 : qty;
  if (existingSkus.has(sku)) {
    stockUpdates.push({ sku, stock_level, supplier_id: 'LLEXETER', updated_at: now });
  } else {
    newSkus.push({ sku, qty });
  }
}

const skipped_new = Math.max(0, newSkus.length - MAX_NEW_PER_RUN);
const newToProcess = newSkus.slice(0, MAX_NEW_PER_RUN);

// ── Step 4: Batch upsert stock updates ───────────────────────
let stock_upserted = 0, stock_errors = 0;

for (let i = 0; i < stockUpdates.length; i += CHUNK_SIZE) {
  const chunk = stockUpdates.slice(i, i + CHUNK_SIZE);
  const res = await fetch(`${SUPABASE_URL}/rest/v1/products`, {
    method: 'POST',
    headers: {
      'apikey':        SERVICE_KEY,
      'Authorization': `Bearer ${SERVICE_KEY}`,
      'Content-Type':  'application/json',
      'Prefer':        'resolution=merge-duplicates,return=minimal'
    },
    body: JSON.stringify(chunk)
  });
  if (res.ok) {
    stock_upserted += chunk.length;
  } else {
    stock_errors += chunk.length;
    console.error('Stock upsert chunk error:', await res.text());
  }
}

// ── Step 5: Enrich & insert new products ─────────────────────
const newProducts = [];
let skipped_price = 0, skipped_fastener = 0, skipped_discontinued = 0;

for (const { sku, qty } of newToProcess) {
  let p;
  try {
    const res = await fetch(`${LLEXETER_BASE}/code/${encodeURIComponent(sku)}`);
    p = await res.json();
  } catch (err) {
    console.error(`Failed to fetch /code/${sku}:`, err.message);
    continue;
  }

  if (p.discontinued === '1') { skipped_discontinued++; continue; }

  const price = parseFloat(p.retail_price) || 0;
  if (price < MIN_PRICE) { skipped_price++; continue; }

  const title = (p.name || p.fullname || '').toLowerCase();
  if (EXCLUDE_TERMS.some(t => title.includes(t))) { skipped_fastener++; continue; }

  if (!p.images || !p.images[0]) { skipped_noimage = (skipped_noimage||0) + 1; continue; }
    newProducts.push({
    sku,
    title:         p.name || p.fullname || sku,
    retail_price:  price,
    selling_price: price,  // LLExeter retail_price IS the selling price
    trade_price:   null,
    stock_level:   qty <= 3 ? 0 : qty,
    image_url:     (p.images && p.images[0]) ? p.images[0] : null,
    category:      p.category || null,
    supplier_id:   'LLEXETER',
    updated_at:    now
  });
}

// Upsert new products
let new_upserted = 0, new_errors = 0;
for (let i = 0; i < newProducts.length; i += CHUNK_SIZE) {
  const chunk = newProducts.slice(i, i + CHUNK_SIZE);
  const res = await fetch(`${SUPABASE_URL}/rest/v1/products`, {
    method: 'POST',
    headers: {
      'apikey':        SERVICE_KEY,
      'Authorization': `Bearer ${SERVICE_KEY}`,
      'Content-Type':  'application/json',
      'Prefer':        'resolution=merge-duplicates,return=minimal'
    },
    body: JSON.stringify(chunk)
  });
  if (res.ok) {
    new_upserted += chunk.length;
  } else {
    new_errors += chunk.length;
    console.error('New product upsert error:', await res.text());
  }
}


// Cleanup: remove any LLEXETER products with null image_url
await fetch(`${SUPABASE_URL}/rest/v1/products?supplier_id=eq.LLEXETER&image_url=is.null`, {
  method: 'DELETE',
  headers: {
    'apikey':        SERVICE_KEY,
    'Authorization': `Bearer ${SERVICE_KEY}`,
    'Prefer':        'return=minimal'
  }
});

return [{ json: {
  total_in_stocklist:   allSkus.length,
  existing_updated:     stock_upserted,
  new_found:            newSkus.length,
  new_inserted:         new_upserted,
  new_skipped_cap:      skipped_new,
  skipped_discontinued,
  skipped_price,
  skipped_fastener,
  stock_errors,
  new_errors,
  run_at: now
} }];

